class Solution {
public:
    int numberOfSpecialChars(string word) {
        int n = word.size();
        int count[26] = {0};
        int special = 0;
        for (int i = 0; i < n; i++) {
            char c = tolower(word[i]);
            if (count[c - 'a'] == 0 && word[i] != tolower(word[i])) {
                special++;
            }
            count[c - 'a']++;
        }
        return special;
    }
};
```

